import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

public class XSSSecureCode {

    public static void main(String[] args) {
        // Simulating user input from a form submission
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Sanitize user input using OWASP Java HTML Sanitizer library
        PolicyFactory policy = Sanitizers.FORMATTING.and(Sanitizers.LINKS);
        String sanitizedInput = policy.sanitize(userInput);

        // Properly handling and outputting sanitized user input to a web page
        String output = "<div>" + sanitizedInput + "</div>";

        // Display the sanitized output on the web page
        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
